import{_ as t,o as a,c as i,a2 as r}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"漏斗、留存、错误率、性能与 AI 成本分析","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"product-analytics-metrics"},"headers":[],"relativePath":"05-backend-data/notes/07-cache-messaging-storage/23-product-analytics-metrics.md","filePath":"05-backend-data/notes/07-cache-messaging-storage/23-product-analytics-metrics.md","lastUpdated":1784542968000}'),o={name:"05-backend-data/notes/07-cache-messaging-storage/23-product-analytics-metrics.md"};function n(l,e,d,s,c,h){return a(),i("div",null,[...e[0]||(e[0]=[r(`<h1 id="漏斗、留存、错误率、性能与-ai-成本分析" tabindex="-1">漏斗、留存、错误率、性能与 AI 成本分析 <a class="header-anchor" href="#漏斗、留存、错误率、性能与-ai-成本分析" aria-label="Permalink to &quot;漏斗、留存、错误率、性能与 AI 成本分析&quot;">​</a></h1><p>指标只有在事件定义、主体、时间窗、去重、分母和版本一致时才可比较。产品漏斗与留存描述行为队列，错误率和性能描述服务质量，AI成本连接请求、token、缓存、重试和业务结果。</p><h2 id="_1-数据流与决策边界" tabindex="-1">1. 数据流与决策边界 <a class="header-anchor" href="#_1-数据流与决策边界" aria-label="Permalink to &quot;1. 数据流与决策边界&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> A[&quot;源事实/事件&quot;] --&gt; B[&quot;传输与处理&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> B --&gt; C[&quot;模型/存储&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> C --&gt; D[&quot;查询与指标&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> D --&gt; E[&quot;质量、对账与重建&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>产品指标是事件契约、主体、时间窗、分母、去重和归因规则的可执行定义。漏斗、留存、错误率、延迟与 AI 成本必须保存 metric version 和适用时间；同名数字若口径不同就不是同一指标，刷新看板不能无说明地改写历史。</p><h2 id="_2-事件契约" tabindex="-1">2. 事件契约 <a class="header-anchor" href="#_2-事件契约" aria-label="Permalink to &quot;2. 事件契约&quot;">​</a></h2><p>机制：event name、ID、subject、occurred/ingested time、properties和schema。</p><p>实际用途：可重放一致计算。</p><p>失败方式：客户端任意字段/重复发送。</p><p>验证：schema测试、重复率、版本分布。</p><p>取舍：治理增加埋点成本。</p><p>事件契约 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_3-identity" tabindex="-1">3. Identity <a class="header-anchor" href="#_3-identity" aria-label="Permalink to &quot;3. Identity&quot;">​</a></h2><p>机制：anonymous/device/user/account映射和合并规则。</p><p>实际用途：跨登录旅程。</p><p>失败方式：把设备数当用户数或错误合并共享设备。</p><p>验证：identity merge审计和敏感最小化。</p><p>取舍：完整旅程与隐私风险。</p><p>Identity 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_4-funnel" tabindex="-1">4. Funnel <a class="header-anchor" href="#_4-funnel" aria-label="Permalink to &quot;4. Funnel&quot;">​</a></h2><p>机制：有序步骤、窗口、主体和去重定义。</p><p>实际用途：注册/购买转化。</p><p>失败方式：分母/顺序/跨设备定义变化。</p><p>验证：SQL样例与手工cohort。</p><p>取舍：直观但易受选择偏差。</p><p>Funnel 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_5-retention" tabindex="-1">5. Retention <a class="header-anchor" href="#_5-retention" aria-label="Permalink to &quot;5. Retention&quot;">​</a></h2><p>机制：cohort起点后第N日/周返回行为。</p><p>实际用途：激活和长期价值。</p><p>失败方式：rolling/classic混用。</p><p>验证：固定cohort/timezone/return event。</p><p>取舍：衡量粘性但窗口选择影响。</p><p>Retention 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_6-error-rate" tabindex="-1">6. Error rate <a class="header-anchor" href="#_6-error-rate" aria-label="Permalink to &quot;6. Error rate&quot;">​</a></h2><p>机制：失败请求/有效尝试，按route/status/problem分类。</p><p>实际用途：SLO和发布质量。</p><p>失败方式：把重试请求重复计分母或200业务失败漏掉。</p><p>验证：服务端结果和trace抽样。</p><p>取舍：可告警但需业务错误分层。</p><p>Error rate 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_7-latency" tabindex="-1">7. Latency <a class="header-anchor" href="#_7-latency" aria-label="Permalink to &quot;7. Latency&quot;">​</a></h2><p>机制：p50/p95/p99和分布，端到端与组件分别测。</p><p>实际用途：性能SLO与尾延迟。</p><p>失败方式：平均值掩盖长尾。</p><p>验证：histogram桶、单位和采样点验证。</p><p>取舍：高分位需足够样本。</p><p>Latency 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_8-ai-tokens" tabindex="-1">8. AI tokens <a class="header-anchor" href="#_8-ai-tokens" aria-label="Permalink to &quot;8. AI tokens&quot;">​</a></h2><p>机制：输入、缓存输入、输出和推理等按供应商计费字段。</p><p>实际用途：请求/功能/tenant成本。</p><p>失败方式：用字符估token或忽略重试。</p><p>验证：账单/usage字段对账。</p><p>取舍：精确成本依API和价格版本。</p><p>AI tokens 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_9-ai-quality-cost" tabindex="-1">9. AI quality/cost <a class="header-anchor" href="#_9-ai-quality-cost" aria-label="Permalink to &quot;9. AI quality/cost&quot;">​</a></h2><p>机制：单位成功任务成本而非单请求成本。</p><p>实际用途：模型路由与优化。</p><p>失败方式：只降token却降低成功率导致重试。</p><p>验证：固定评估集+线上结果+总成本。</p><p>取舍：需要质量、延迟、成本联合。</p><p>AI quality/cost 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_10-attribution" tabindex="-1">10. Attribution <a class="header-anchor" href="#_10-attribution" aria-label="Permalink to &quot;10. Attribution&quot;">​</a></h2><p>机制：实验/渠道归因窗口和规则。</p><p>实际用途：产品决策。</p><p>失败方式：观察相关性宣称因果。</p><p>验证：随机实验/混杂分析。</p><p>取舍：可行动但规则敏感。</p><p>Attribution 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_11-metric-version" tabindex="-1">11. Metric version <a class="header-anchor" href="#_11-metric-version" aria-label="Permalink to &quot;11. Metric version&quot;">​</a></h2><p>机制：定义、SQL、时区、数据源和生效时间版本化。</p><p>实际用途：可复现历史看板。</p><p>失败方式：同名指标悄然改定义。</p><p>验证：semantic tests和版本对比。</p><p>取舍：维护成本换可信度。</p><p>Metric version 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_12-方案比较" tabindex="-1">12. 方案比较 <a class="header-anchor" href="#_12-方案比较" aria-label="Permalink to &quot;12. 方案比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>主要能力</th><th>边界</th></tr></thead><tbody><tr><td>事件数</td><td>简单</td><td>受重复影响</td></tr><tr><td>用户数</td><td>主体去重</td><td>identity复杂</td></tr><tr><td>classic retention</td><td>固定周期返回</td><td>严格</td></tr><tr><td>rolling retention</td><td>某日后任意返回</td><td>更高不可混比</td></tr><tr><td>每请求AI成本</td><td>工程优化</td><td>不代表业务价值</td></tr><tr><td>每成功任务成本</td><td>连接质量</td><td>定义更复杂</td></tr></tbody></table><h2 id="_13-完整案例-新用户激活漏斗与留存" tabindex="-1">13. 完整案例：新用户激活漏斗与留存 <a class="header-anchor" href="#_13-完整案例-新用户激活漏斗与留存" aria-label="Permalink to &quot;13. 完整案例：新用户激活漏斗与留存&quot;">​</a></h2><h3 id="输入与约束" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>步骤signup→create_project→invite_member，7天窗口；跨时区；匿名后登录合并。</p><h3 id="处理步骤" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>定义主体为account_id，signup为cohort起点，事件ID去重。</li><li>occurred_at统一UTC，按产品业务时区分日。</li><li>每步骤要求前一步后且7天内，重复只取首次。</li><li>D1/D7 classic retention以active_project事件定义。</li><li>按schema/客户端版本监控缺失和迟到，SQL版本化。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>漏斗和留存可按cohort/版本复现，不因看板刷新改历史。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>手工20账户golden set；跨午夜、重复、晚到和identity merge样例。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>用任意顺序存在步骤会把先邀请后建项目的脏事件计转化；必须实现顺序/窗口。</p><h3 id="恢复与重跑" tabindex="-1">恢复与重跑 <a class="header-anchor" href="#恢复与重跑" aria-label="Permalink to &quot;恢复与重跑&quot;">​</a></h3><p>事件修复按 event ID 幂等写入原始层，identity merge 使用可版本化映射，不直接覆盖历史主体。候选 metric version 在固定 cohort 和截止水位重算，与 golden accounts 逐步对比；确认变化来自明确的事件或口径修订后再发布，并在看板标注版本生效日。</p><h2 id="_14-完整案例-ai客服成本与质量" tabindex="-1">14. 完整案例：AI客服成本与质量 <a class="header-anchor" href="#_14-完整案例-ai客服成本与质量" aria-label="Permalink to &quot;14. 完整案例：AI客服成本与质量&quot;">​</a></h2><h3 id="输入与约束-1" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束-1" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>模型多版本、工具调用和重试；需要每解决工单成本、p95、解决率，不能泄露正文。</p><h3 id="处理步骤-1" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤-1" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>每turn记录request ID、model/version、token分类、latency、status和价格表版本。</li><li>以ticket ID聚合所有重试/工具/降级总成本。</li><li>成功由受控resolution/评估规则定义，不以模型自报。</li><li>离线固定集比较质量，线上按工单类型/tenant观察。</li><li>成本报表用账单usage对账，正文脱敏/不入指标。</li></ol><h3 id="输出-1" tabindex="-1">输出 <a class="header-anchor" href="#输出-1" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>能比较每成功工单总成本、质量和延迟，而非单次便宜。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>重试成本被计入；缓存token按供应商usage；价格变更不改旧历史。</p><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>仅比较每请求token会奖励失败后多次重试的便宜模型；使用unit successful outcome。</p><h3 id="恢复与重跑-1" tabindex="-1">恢复与重跑 <a class="header-anchor" href="#恢复与重跑-1" aria-label="Permalink to &quot;恢复与重跑&quot;">​</a></h3><p>usage 回填以 provider request ID、账单行 ID 和价格表版本去重，重新聚合 ticket 的全部重试与工具调用。质量规则或价格修订生成新的计算版本，先对账供应商账单总额和固定评估集；发布后保留旧版本，避免用今天的价格重写历史成本却不留痕。</p><h2 id="_15-失败注入矩阵" tabindex="-1">15. 失败注入矩阵 <a class="header-anchor" href="#_15-失败注入矩阵" aria-label="Permalink to &quot;15. 失败注入矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>注入</th><th>预期信号与恢复</th><th>禁止结果</th></tr></thead><tbody><tr><td>重复输入</td><td><code>event_duplicate</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>乱序和迟到</td><td><code>schema_version</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>源schema变化</td><td><code>identity_merge</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>任务中途崩溃</td><td><code>funnel_conversion</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>下游429/503</td><td><code>retention_d7</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>checkpoint损坏</td><td><code>error_rate</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>质量规则失败</td><td><code>latency_p99</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>回填与实时并发</td><td><code>ai_cost_total</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>权限撤销</td><td><code>cost_per_success</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>成本超预算</td><td><code>metric_diff</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr></tbody></table><h2 id="_16-数据质量与对账" tabindex="-1">16. 数据质量与对账 <a class="header-anchor" href="#_16-数据质量与对账" aria-label="Permalink to &quot;16. 数据质量与对账&quot;">​</a></h2><ol><li>事件 ID 在定义的保留窗口内唯一，重复率按事件名、客户端和 schema version 拆分，不能在指标 SQL 中无声去重。</li><li>必填主体、occurred_at、event name 和关键属性缺失时进入隔离；匿名事件允许的主体规则单独声明。</li><li>客户端时间与接收时间的偏差、迟到分布和未来时间戳分别监控，超出窗口的修正策略写入口径。</li><li>identity merge 检查一对多冲突与循环，发布前用已知账户验证匿名到登录后的事件归属。</li><li>漏斗 golden set 覆盖顺序、重复步骤、窗口边界和跨时区，逐账户结果与人工预期一致。</li><li>留存的 cohort 起点、活跃事件、周期边界和观察完整性明确；尚未走完整窗口的 cohort 不进最终分母。</li><li>错误率分母使用实际尝试请求，timeout、取消、重试和降级分别编码，禁止只统计有响应的请求。</li><li>延迟分位数基于原始请求样本或可合并分布计算，不能平均各分片 p95；采样率变化需可见。</li><li>AI usage 按 request、turn、ticket 三层对账，token 分类与供应商账单总量差异超过预算阈值时阻断成本发布。</li><li>metric version 发布前运行旧新口径双算，输出变化最大的 cohort/tenant 和原因，审核后标注生效范围。</li></ol><h2 id="_17-调试与观测" tabindex="-1">17. 调试与观测 <a class="header-anchor" href="#_17-调试与观测" aria-label="Permalink to &quot;17. 调试与观测&quot;">​</a></h2><ol><li><code>event_duplicate</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>schema_version</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>identity_merge</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>funnel_conversion</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>retention_d7</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>error_rate</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>latency_p99</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>ai_cost_total</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>cost_per_success</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>metric_diff</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li></ol><p>指标异常先固定 metric version、cohort 和截止水位，再选 account/ticket 逐条核对原始事件、去重、identity mapping、时间窗、分母与聚合 SQL。AI 成本还要追 request ID 到 usage 和价格表；总看板波动不能告诉你是埋点缺失、口径变化还是产品行为变化。</p><h2 id="_18-安全、成本与运维边界" tabindex="-1">18. 安全、成本与运维边界 <a class="header-anchor" href="#_18-安全、成本与运维边界" aria-label="Permalink to &quot;18. 安全、成本与运维边界&quot;">​</a></h2><ol><li>源凭据最小权限；漏斗、留存、错误率、性能与 AI 成本分析 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>PII分层访问和脱敏；漏斗、留存、错误率、性能与 AI 成本分析 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>原始层不可被普通BI任意下载；漏斗、留存、错误率、性能与 AI 成本分析 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>重跑/回填有资源配额；漏斗、留存、错误率、性能与 AI 成本分析 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>流批共享sink有容量仲裁；漏斗、留存、错误率、性能与 AI 成本分析 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>删除请求传播到派生层；漏斗、留存、错误率、性能与 AI 成本分析 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>schema发布兼容门禁；漏斗、留存、错误率、性能与 AI 成本分析 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>checkpoint/manifest备份；漏斗、留存、错误率、性能与 AI 成本分析 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>灾备恢复演练；漏斗、留存、错误率、性能与 AI 成本分析 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>成本按pipeline/dataset/tenant归集；漏斗、留存、错误率、性能与 AI 成本分析 的实现要提供owner、runbook、停止阈值和审计记录。</li></ol><h2 id="_19-综合练习与验收" tabindex="-1">19. 综合练习与验收 <a class="header-anchor" href="#_19-综合练习与验收" aria-label="Permalink to &quot;19. 综合练习与验收&quot;">​</a></h2><p>实现“新用户激活漏斗与留存”，再以“AI客服成本与质量”验证另一类时效/治理约束。提交数据样例、模型、质量测试、故障注入、lineage和成本面板。</p><ul><li>[ ] 事件契约 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Identity 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Funnel 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Retention 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Error rate 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Latency 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] AI tokens 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] AI quality/cost 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] 两个案例包含输入、步骤、输出、验证、失败与重跑。</li><li>[ ] 源与目标按业务分片完成count/sum/version/hash对账。</li><li>[ ] 历史发布版本可回退，回填不压垮在线事实系统。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://opentelemetry.io/docs/specs/otel/metrics/" target="_blank" rel="noreferrer">OpenTelemetry Metrics specification</a>（访问日期：2026-07-17）</li><li><a href="https://opentelemetry.io/docs/specs/semconv/http/" target="_blank" rel="noreferrer">OpenTelemetry semantic conventions HTTP</a>（访问日期：2026-07-17）</li><li><a href="https://nightlies.apache.org/flink/flink-docs-stable/docs/concepts/time/" target="_blank" rel="noreferrer">Apache Flink event time docs</a>（访问日期：2026-07-17）</li><li><a href="https://docs.getdbt.com/docs/use-dbt-semantic-layer/dbt-sl" target="_blank" rel="noreferrer">dbt Semantic Layer</a>（访问日期：2026-07-17）</li><li><a href="https://openlineage.io/docs/spec/" target="_blank" rel="noreferrer">OpenLineage specification</a>（访问日期：2026-07-17）</li></ul>`,117)])])}const b=t(o,[["render",n]]);export{u as __pageData,b as default};
